#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    long long key;
    long long value;
    struct Node* next;
} Node;

#define TABLE_SIZE 200003
static Node* table[TABLE_SIZE];

static unsigned int hash_key(long long x) {
    return (unsigned int)((x ^ (x >> 32)) % TABLE_SIZE);
}

static long long get(long long key) {
    unsigned int h = hash_key(key);
    for (Node* p = table[h]; p; p = p->next) {
        if (p->key == key) return p->value;
    }
    return 0;
}

static void inc(long long key) {
    unsigned int h = hash_key(key);
    for (Node* p = table[h]; p; p = p->next) {
        if (p->key == key) { p->value++; return; }
    }
    Node* n = (Node*)malloc(sizeof(Node));
    n->key = key; n->value = 1; n->next = table[h];
    table[h] = n;
}

static void clearTable() {
    for (int i = 0; i < TABLE_SIZE; ++i) {
        Node* p = table[i];
        while (p) {
            Node* nxt = p->next;
            free(p);
            p = nxt;
        }
        table[i] = NULL;
    }
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; long long k; scanf("%d %lld", &n, &k);
        clearTable();
        inc(0); // prefix 0 occurs once
        long long prefix = 0, ans = 0;
        for (int i = 0; i < n; ++i) {
            long long x; scanf("%lld", &x);
            prefix ^= x;
            ans += get(prefix ^ k);
            inc(prefix);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

